INSERT INTO public."RoutingRule" (id, name, description, "strategyType", config, "matchConditions", priority, "pipelineStage", "fallbackChain", enabled, "createdAt", "updatedAt", "retryPolicy") VALUES ('08272024-eea1-464e-bbb0-a828c64a1c1e', 'smart-auto-routing', 'AI router analyzes user prompt and selects the best model when model is "auto"', 'smart', '{"type": "smart", "maxTokens": 1024, "timeoutMs": 10000, "temperature": 0, "systemPrompt": "You are an AI model router for an enterprise gateway. Select the best model for the user''s request.\n\n## Available Models\n{modelCatalog}\n\n## Selection Rules\n1. Analyze the task: coding, analysis, creative writing, Q&A, translation, math, reasoning\n2. Match capabilities: images → vision, tools → function_calling, long text → large context\n3. Cost: simple tasks → cheapest capable model; complex tasks → most capable\n4. If uncertain, prefer the most capable model\n\nCRITICAL: keep the \"reason\" field under 30 words. Do not analyse the user''s request itself. Classify the task type only.\n\n## Output Format\nReturn ONLY valid JSON: {\"modelId\": \"<exact ID from list>\", \"reason\": \"<brief explanation>\"}", "routerModelId": "06056793-2ab1-4975-a0db-66896ca56134", "defaultModelId": "3f45ca57-c842-4e40-a901-4d607f3fe064", "routerProviderId": "6b6d307f-a80b-4dcb-801b-1ffa07e25cab", "defaultProviderId": "6b6d307f-a80b-4dcb-801b-1ffa07e25cab"}', '{"requestedModelLiterals": ["auto"]}', 25, 1, '[{"modelId": "3f45ca57-c842-4e40-a901-4d607f3fe064", "providerId": "6b6d307f-a80b-4dcb-801b-1ffa07e25cab"}, {"modelId": "ca94f1a2-8a03-499b-b7b8-433621e8504a", "providerId": "64119a02-f3e4-4ff3-a023-e2289bc3135c"}]', true, '2026-05-08 14:45:53.082+00', '2026-05-14 17:12:19.657+00', NULL);
