INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('enrollment-cleanup', 'Enrollment Token Cleanup', 'Marks expired pending agent enrollment tokens as expired.', 3600, true, '2026-05-08 14:46:38.166+00', '2026-05-16 02:48:53.143+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('thing-offline-alerts', 'Thing Offline Alerts', 'Raises thing.offline alerts for Things whose last_seen_at has exceeded the rule''s offlineAfterSec threshold; auto-resolves firing alerts for Things that have come back fresh or have been deleted.', 60, true, '2026-05-08 14:46:38.164+00', '2026-05-16 02:48:53.114+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('ops-rollup-1mo', 'Ops Metrics Rollup (1 month)', 'Aggregates metric_ops_rollup_1d into metric_ops_rollup_1mo once per day, using calendar-month bucket boundaries (28-31 days). The current (unsealed) month is always excluded.', 86400, true, '2026-05-08 14:46:38.179+00', '2026-05-16 02:48:53.12+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('ops-retention', 'Ops Metrics & Diag Retention Purge', 'Purges aged metric_ops_rollup_5m/1h/1d/1mo and thing_diag_event rows. Per-class retention is read live from metric_ops_retention_config (one row per layer: runtime_5m, business_5m, runtime_1h, business_1h, runtime_1d, business_1d, runtime_1mo, business_1mo, diag_info, diag_warn, diag_error, diag_fatal). Deletes run in chunks of 10k rows so transactions stay short. The metric_ops_raw table is NOT purged here — it is partition-dropped by the ops-raw-partition job.', 86400, true, '2026-05-08 14:46:38.18+00', '2026-05-16 02:48:53.101+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('audit-chain-verify', 'Audit Chain Verify', 'Walks the AdminAuditLog hash chain and reports tamper detection.', 3600, true, '2026-05-08 14:46:38.169+00', '2026-05-16 02:48:53.103+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('data-retention', 'Data Retention Purge', 'Deletes audit and rollup rows older than the configured retention period each day.', 86400, true, '2026-05-08 14:46:38.185+00', '2026-05-16 02:48:53.118+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('job-retention', 'Job Run History Retention', 'Prunes job_run rows, keeping the N most recent runs per job.', 86400, true, '2026-05-08 14:46:38.19+00', '2026-05-16 02:48:53.105+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('agent-cert-expiration-alerts', 'Agent Cert Expiration Alerts', 'Polls thing_agent.cert_expires_at for desktop-agent Things and raises agent.cert_expiration_imminent alerts as the expiry approaches each warn-day threshold (default 30 / 14 / 7 / 1 days). Auto-resolves when the cert is renewed.', 3600, true, '2026-05-08 14:46:38.193+00', '2026-05-16 02:48:53.121+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('merge-1mo', 'Rollup Merge (1 day → 1 month)', 'Merges metric_rollup_1d into metric_rollup_1mo once per day, using calendar-month bucket boundaries.', 86400, true, '2026-05-08 14:46:38.188+00', '2026-05-16 02:48:53.139+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('auth-cleanup', 'Auth Token Cleanup', 'Deletes expired refresh and revoked token rows every hour.', 3600, true, '2026-05-08 14:46:38.165+00', '2026-05-16 02:48:53.117+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('vk-expiry', 'Virtual Key Expiry', 'Expires virtual keys past their expiry date and raises quota.vk_expiring alerts for keys expiring within the warn window; auto-resolves once a key has been renewed or is no longer within the window.', 3600, true, '2026-05-08 14:46:38.181+00', '2026-05-16 02:48:53.102+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('provider-unavailable-alerts', 'Provider Unavailable Alerts', 'Raises provider.unavailable alerts for Providers whose ProviderHealth status is ''unavailable''; auto-resolves firing alerts when the provider recovers to healthy, recovering, or degraded.', 60, true, '2026-05-08 14:46:38.182+00', '2026-05-16 02:48:53.137+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('rollup-5m', 'Traffic Rollup (5 minute)', 'Aggregates traffic_event rows into metric_rollup_5m every minute, catching up from the last committed bucket to the most recent sealed 5-minute bucket.', 60, true, '2026-05-08 14:46:38.187+00', '2026-05-16 02:48:53.145+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('config-drift-check', 'Config Drift Detection', 'Detects Things whose reported config version differs from desired and triggers repair.', 60, true, '2026-05-08 14:46:38.162+00', '2026-05-16 02:48:53.109+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('rollup-retention', 'Rollup Retention Purge', 'Purges aged rows from metric_rollup_5m/1h/1d/1mo tables based on per-tier retention days.', 86400, true, '2026-05-08 14:46:38.17+00', '2026-05-16 02:48:53.13+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('cache-quality-monitor', 'Cache Quality Monitor', 'Detects elevated error rates in normaliser-modified requests over the past 30 minutes and auto-reverts all active rules to dry_run_always when the error rate exceeds 3× baseline, preventing normaliser-induced quality regressions.', 300, true, '2026-05-08 14:46:38.168+00', '2026-05-16 02:48:53.124+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('diag-mode-expiry', 'Diagnostic Mode Expiry', 'Clears the diagModeUntil flag from thing.metadata once the corresponding thing_diag_mode_window has ended. Runs every minute; mutations are atomic per thing (no batch transaction).', 60, true, '2026-05-08 14:46:38.163+00', '2026-05-16 02:48:53.135+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('user-identity-enrichment', 'User Identity Enrichment', 'Backfills user identity fields into recent traffic_event rows using IAM lookups.', 300, true, '2026-05-08 14:46:38.177+00', '2026-05-16 02:48:53.11+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('alerteval-engine', 'Alert Evaluator (Streaming)', 'Subscribes to MQ traffic + audit events under consumer group hub-alerting, maintains in-memory ring buffers per registered Aggregator, and evaluates threshold rules every tick (default 5s).', 10, true, '2026-05-08 14:46:38.175+00', '2026-05-16 02:48:53.128+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('stale-thing-sweep', 'Stale Thing Sweep', 'Marks Things offline when their last_seen_at exceeds the per-category threshold.', 30, true, '2026-05-08 14:46:38.184+00', '2026-05-16 02:48:53.104+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('rollup-correction', 'Rollup Correction', 'Recomputes rollups for T-1 (yesterday) to absorb late-arriving events. Re-runs every 5-minute bucket, then re-merges the 1h, 1d, and (on month boundary) 1mo layers.', 86400, true, '2026-05-08 14:46:38.172+00', '2026-05-16 02:48:53.119+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('ops-rollup-1d', 'Ops Metrics Rollup (1 day)', 'Aggregates metric_ops_rollup_1h into metric_ops_rollup_1d every hour. Sample-count-weighted averages; histograms merge element-wise. The fleet vs per-thing distinction (thing_id NULL vs not) is preserved from the 1h layer.', 3600, true, '2026-05-08 14:46:38.176+00', '2026-05-16 02:48:53.134+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('merge-1d', 'Rollup Merge (1 hour → 1 day)', 'Merges metric_rollup_1h into metric_rollup_1d every hour, catching up from the persisted watermark to the most recent sealed 1-day bucket.', 3600, true, '2026-05-08 14:46:38.167+00', '2026-05-16 02:48:53.138+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('metrics-rollup', 'Device Metrics Rollup', 'Aggregates device fleet status/OS and agent action volume into metric_rollup_1h every hour.', 3600, true, '2026-05-08 14:46:38.186+00', '2026-05-16 02:48:53.144+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('merge-1h', 'Rollup Merge (5 minute → 1 hour)', 'Merges metric_rollup_5m into metric_rollup_1h every 5 minutes, catching up from the persisted watermark to the most recent sealed 1-hour bucket.', 300, true, '2026-05-08 14:46:38.171+00', '2026-05-16 02:48:53.111+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('exemption-gc', 'Active Exemption Garbage Collection', 'Fires a Cat B invalidate signal when compliance exemption grants have recently expired so compliance-proxy refreshes its in-memory view without waiting for the next admin mutation.', 300, true, '2026-05-08 14:46:38.191+00', '2026-05-16 02:48:53.106+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('override-expiry', 'Override Expiry', 'Clears thing_config_override rows past their expires_at.', 60, true, '2026-05-08 14:46:38.189+00', '2026-05-16 02:48:53.142+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('quota-alert-check', 'Quota Alert Check', 'Evaluates current-month cost usage against QuotaOverride and QuotaPolicy cost limits every minute and raises quota.threshold alerts when usage crosses configured thresholds; auto-resolves with 2pp hysteresis once usage falls back.', 60, true, '2026-05-08 14:46:38.192+00', '2026-05-16 02:48:53.126+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('provider-health-rollup', 'Provider Health Rollup', 'Recomputes ProviderHealth (error rate, avg latency, sample count, status) from traffic_event over a 30-minute rolling window. Replaces the AI Gateway in-process HealthTracker DB flush.', 300, true, '2026-05-08 14:46:38.174+00', '2026-05-16 02:48:53.108+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('ops-rollup-1h', 'Ops Metrics Rollup (1 hour)', 'Aggregates metric_ops_rollup_5m into metric_ops_rollup_1h every 5 minutes. Sample-count-weighted averages; histograms merge element-wise. The fleet vs per-thing distinction (thing_id NULL vs not) is preserved from the 5m layer.', 300, true, '2026-05-08 14:46:38.173+00', '2026-05-16 02:48:53.133+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('ops-rollup-5m', 'Ops Metrics Rollup (5 minute)', 'Aggregates metric_ops_raw into metric_ops_rollup_5m every minute. Services keep per-instance rows; agents keep per-instance rows only when in diagnostic mode for the bucket and otherwise collapse into a single fleet-aggregate row (thing_id IS NULL) per metric+dimension. The 1h/1d/1mo tiers cascade from this 5m layer.', 60, true, '2026-05-08 14:46:38.173+00', '2026-05-16 02:48:53.133+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('ops-raw-partition', 'Ops Raw Partition Maintenance', 'Maintains the daily RANGE partitions of metric_ops_raw: pre-creates upcoming day partitions and DROPs partitions older than the configured retention horizon (NEXUS_HUB_SCHEDULER_OPS_RAW_DAYS, default 30 days). Replaces the chunked row-by-row DELETE for raw ops-metric samples — dropping a whole-day partition is an O(1) metadata operation.', 21600, true, '2026-05-08 14:46:38.173+00', '2026-05-16 02:48:53.133+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('thing-merge-1mo', 'Per-Thing Rollup Merge (1 day → 1 month)', 'Merges thing_metric_rollup_1d into thing_metric_rollup_1mo daily with calendar-month bucket boundaries.', 86400, true, '2026-05-13 10:54:32.703+00', '2026-05-16 02:48:53.125+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('passthrough.expiry', 'Passthrough Expiry Auto-Revert', 'Flips enabled=false on emergency-passthrough rows whose expires_at has passed across global/adapter/provider tiers.', 60, true, '2026-05-13 14:37:36.569+00', '2026-05-16 02:48:53.127+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('audit-freshness-check', 'Audit Pipeline Freshness Check', 'Alerts when traffic_event hasn''t seen new rows within the configured threshold.', 60, true, '2026-05-14 10:36:46.952+00', '2026-05-16 02:48:53.129+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('thing-rollup-5m', 'Per-Thing Traffic Rollup (5 minute)', 'Aggregates traffic_event rows with thing_id into thing_metric_rollup_5m every minute, mirroring rollup-5m but keyed by (thing_id, metric, dim, sub-dim).', 60, true, '2026-05-13 10:54:32.7+00', '2026-05-16 02:48:53.098+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('thing-merge-1h', 'Per-Thing Rollup Merge (5 minute → 1 hour)', 'Merges thing_metric_rollup_5m into thing_metric_rollup_1h every 5 minutes, mirroring merge-1h.', 300, true, '2026-05-13 10:54:32.727+00', '2026-05-16 02:48:53.099+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('credential-stale-alerts', 'Credential Stale Last-Success Alerts', 'Polls Credential.lastSuccessAt for enabled credentials and raises credential.stale_last_success alerts when no successful use in params.staleAfterDays. Auto-resolves once a credential is used successfully again.', 3600, true, '2026-05-08 14:46:38.179+00', '2026-05-16 02:48:53.107+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('thing-merge-1d', 'Per-Thing Rollup Merge (1 hour → 1 day)', 'Merges thing_metric_rollup_1h into thing_metric_rollup_1d every hour, mirroring merge-1d.', 3600, true, '2026-05-13 10:54:32.701+00', '2026-05-16 02:48:53.113+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('smart-group-recompute', 'Smart Group Membership Recompute', 'E52-S2: re-evaluates every smart DeviceGroup''s membership_query against the current device fleet and replaces the device_group_membership_cache rows. Runs every 60s as a safety net; heartbeat-driven recomputes handle the steady-state.', 60, true, '2026-05-14 10:36:46.978+00', '2026-05-16 02:48:53.131+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('credential-expiry', 'Credential Expiry Check', 'Advances rotationState to ''pending_rotation'' and raises credential.expiring alerts for credentials approaching their expiresAt. Raises CRITICAL alerts for overdue credentials (no auto-disable). Auto-resolves once a credential is no longer in the expiring set.', 3600, true, '2026-05-10 16:08:54.305+00', '2026-05-16 02:48:53.136+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('credential-circuit-flush', 'Credential Circuit Flush', 'Drains cred:circuit:dirty into Credential.circuit* columns. Uses an in-flight working set for at-least-once delivery. Rehydrates Redis from DB on first run after restart. See docs/developers/architecture/control-plane/credentials-architecture.md.', 30, true, '2026-05-13 04:21:03.036+00', '2026-05-16 02:48:53.14+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('siem-bridge', 'SIEM Bridge', 'Polls traffic_event and AdminAuditLog for new rows, classifies them, and forwards them to the configured SIEM sink. Checkpoints are persisted in system_metadata.', 30, true, '2026-05-13 04:21:03.056+00', '2026-05-16 02:48:53.141+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('credential-stats-flush', 'Credential Stats Flush', 'Drains per-credential usage counters and timestamps from Redis into the Credential table. Runs frequently to keep lastUsedAt, lastSuccessAt, lastFailureAt, and totalUsageCount up to date without high-frequency concurrent DB writes.', 60, true, '2026-05-11 06:30:58.606+00', '2026-05-16 02:48:53.115+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('credential-reliability-alerts', 'Credential Reliability Alerts', 'Raises credential.circuit_open, credential.health_unavailable, and credential.health_degraded_sustained alerts from the persisted reliability state on the Credential table. See docs/developers/architecture/control-plane/credentials-architecture.md.', 60, true, '2026-05-13 04:21:03.037+00', '2026-05-16 02:48:53.116+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('credential-health-rollup', 'Credential Health Rollup', 'Computes per-credential health (healthy / degraded / unavailable / collecting / unknown), dominantError, and trend (improving / stable / degrading) from traffic_event over a short (5 min) and long (1 h) window. Persists to Credential.health* columns; only rows whose status changed update healthStatusChangedAt. See docs/developers/architecture/control-plane/credentials-architecture.md.', 300, true, '2026-05-13 04:21:03.062+00', '2026-05-16 02:48:53.122+00');
INSERT INTO public.job (id, name, description, "intervalSec", enabled, "createdAt", "updatedAt") VALUES ('credential-retire', 'Credential Retire', 'Advances credentials from retiring → retired (after drain window) and hard-deletes retired credentials past their retireAt date.', 3600, true, '2026-05-11 06:30:58.589+00', '2026-05-16 02:48:53.123+00');
