INSERT INTO public.rule_pack (id, name, version, maintainer, description, signature, "createdAt") VALUES ('75cf6ec8-0035-4a44-9109-6d89b1dab920', 'nexus/content-safety', 'v1.0.0', 'nexus', 'Content-safety patterns across 5 restricted categories: violence, hate_speech, self_harm, sexual, illegal. Each rule emits `detector:content-safety`, `category:<name>`, and `severity:restricted` labels. Patterns are intentionally contextual (verb + target / how-to framing) to keep idiomatic business text — "kill the process", "attack the problem", "human trafficking survivor", "the book covers the Holocaust" — out of the match set. Severity defaults to `soft`; the P-E content-safety hook escalates via AI Guard when configured.', NULL, '2026-05-08 14:46:10.705+00');
INSERT INTO public.rule_pack (id, name, version, maintainer, description, signature, "createdAt") VALUES ('4c1db5f1-cb03-4150-ac50-e4be221f6005', 'nexus/jailbreak', 'v1.0.0', 'nexus', 'Known jailbreak families — DAN variants, developer-mode, grandma/research pretexts. Shares pattern substrings with nexus/prompt-injection but is shipped as a distinct pack so admins can enable/disable independently.', NULL, '2026-05-08 14:46:13.841+00');
INSERT INTO public.rule_pack (id, name, version, maintainer, description, signature, "createdAt") VALUES ('e63b835a-3b39-42be-8e7d-2d258d26f3f3', 'nexus/prompt-injection', 'v1.0.0', 'nexus', 'Nexus-curated prompt-injection patterns. Covers instruction override, role-play escapes, system-prompt leakage, delimiter confusion, and encoded-payload variants. Day-1 scope is conservative; tune FP after production telemetry.', NULL, '2026-05-08 14:46:16.212+00');
INSERT INTO public.rule_pack (id, name, version, maintainer, description, signature, "createdAt") VALUES ('d4143067-6079-486e-aca2-c61fd0d34335', 'nexus/secret-leak', 'v1.0.0', 'nexus', 'API key and credential patterns for common providers. Day-1 list covers AWS / GCP / Azure / OpenAI / Anthropic / GitHub / Stripe / Slack / SSH / JWT + an optional entropy-gated generic bearer pattern. All rules emit severity:restricted so the pipeline-level severity picker escalates.', NULL, '2026-05-08 14:46:17.793+00');
INSERT INTO public.rule_pack (id, name, version, maintainer, description, signature, "createdAt") VALUES ('34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'nexus/tool-call-safety', 'v1.0.0', 'nexus', 'Tool-call safety patterns for agent / function-calling traffic. Day-1 rules cover shell destructive ops, filesystem sensitive paths, SSRF (cloud metadata + RFC1918 + k8s service names), SQL injection heuristics, code-evaluation primitives, dangerous deserialization, destructive DB DDL, Kubernetes destructive verbs, and credential env-var exfiltration. All rules emit `detector:tool-call-safety` plus a finer `risk:` label so downstream policies can filter by risk class.', NULL, '2026-05-08 14:46:20.432+00');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('10b3d614-e439-4a2c-87e6-e7bbb48f0cc4', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-v-001', 'content_safety.violence', 'soft', '(?i)\b(?:how\s+(?:to|do\s+i)|best\s+way\s+to)\s+(?:murder|assassinate|kill)\s+(?:a\s+person|someone|him|her|them)\b', NULL, 'How-to framing targeting a human (excludes "kill the process" idiom).', '{detector:content-safety,category:violence,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('6842cb99-ddfa-4f13-b972-f1cc724069fd', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-v-002', 'content_safety.violence', 'soft', '(?i)\b(?:bomb|explosive|ied|pipe\s+bomb)\s+(?:making|construction|build(?:ing)?|recipe|instructions?)\b', NULL, 'Weapon / explosive construction how-to.', '{detector:content-safety,category:violence,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('97efee7a-c743-43b0-910d-60099e3b0be3', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-v-003', 'content_safety.violence', 'soft', '(?i)\b(?:shoot|stab|strangle|poison|behead)\s+(?:them|him|her|the\s+(?:victim|target|family|children))\b', NULL, 'Physical-harm verb directed at a human target.', '{detector:content-safety,category:violence,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('cc03d78a-5428-4964-b55a-f3ee6b9e30be', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-v-004', 'content_safety.violence', 'soft', '(?i)\b(?:carry\s+out|plan|organize|execute)\s+(?:a\s+)?(?:massacre|genocide|ethnic\s+cleansing|mass\s+shooting)\b', NULL, 'Mass / group violence planning.', '{detector:content-safety,category:violence,severity:restricted}');
