INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('8e5dd18a-2eef-4e1c-8d82-d8a115900ffb', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-h-001', 'content_safety.hate_speech', 'soft', '(?i)\b(?:tell\s+me|give\s+me|list)\s+(?:a\s+)?(?:racial|ethnic|homophobic|transphobic)\s+slurs?\b', NULL, 'Direct request for slur enumeration.', '{detector:content-safety,category:hate_speech,severity:restricted}');
