INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('0677f2f1-5769-45d4-9a35-cb0f14e0cc65', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-h-003', 'content_safety.hate_speech', 'warn', '(?i)\b(?:white\s+power|white\s+supremac(?:y|ist)|14\s*words|sieg\s+heil|blood\s+and\s+soil)\b', NULL, 'Supremacist / neo-nazi slogan markers.', '{detector:content-safety,category:hate_speech,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('5c971fc9-750e-455b-9504-8b72b0572669', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-h-004', 'content_safety.hate_speech', 'soft', '(?i)\b(?:deport|expel|remove|exterminate)\s+(?:all\s+)?(?:the\s+)?(?:jews|muslims|blacks|gays|immigrants|migrants)\b', NULL, 'Group expulsion / extermination rhetoric.', '{detector:content-safety,category:hate_speech,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('6aca553d-622a-406a-b845-d8cc9347895a', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-h-005', 'content_safety.hate_speech', 'soft', '(?i)\b(?:the\s+)?holocaust\s+(?:didn''?t\s+happen|never\s+happened|is\s+(?:a\s+)?(?:lie|hoax|myth|fake|fabrication)|was\s+(?:faked|fabricated|made\s+up))\b', NULL, 'Holocaust-denial assertion (does NOT match neutral references like "the book discusses the Holocaust").', '{detector:content-safety,category:hate_speech,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('32a5d063-bc98-478b-8a21-a605eea679c4', '75cf6ec8-0035-4a44-9109-6d89b1dab920', 'cs-sh-001', 'content_safety.self_harm', 'soft', '(?i)\b(?:how\s+(?:to|do\s+i)|best\s+way\s+to|easiest\s+way\s+to)\s+(?:commit\s+suicide|kill\s+myself|end\s+my\s+(?:life|existence))\b', NULL, 'Direct suicide how-to request.', '{detector:content-safety,category:self_harm,severity:restricted}');
