INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('7a1921f2-d37d-4b59-affd-4a147d2a8276', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-sh-001', 'tool_call.shell', 'hard', '(?i)\b(rm\s+-rf\s+/|:\(\)\s*\{\s*:\|:&\s*\};:|\|\s*(sh|bash)\s*$)', NULL, 'rm -rf /, classic fork-bomb, or pipe-to-shell tail.', '{detector:tool-call-safety,risk:destructive,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('f50d68ab-c05d-477c-bd8f-9513d2fbf71c', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-sh-002', 'tool_call.shell', 'hard', '\b(?:curl|wget)\s+[^\s|]+\s*\|\s*(?:sh|bash|sudo\s+bash)', NULL, 'curl|wget piped directly to a shell interpreter.', '{detector:tool-call-safety,risk:rce,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('296d0cbc-2144-4548-9290-2a15fc85e312', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-sh-003', 'tool_call.shell', 'soft', '(?i)(shell|bash|system|execve?|popen)\s*\([^)]*(?:rm|dd|mkfs|shutdown|reboot)', NULL, 'System-call wrappers invoked with destructive verbs.', '{detector:tool-call-safety,risk:destructive,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('0d16e588-fb50-4dd1-af1b-8595db3215d8', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-fs-001', 'tool_call.filesystem', 'hard', '(?i)(?:write|open|create|append)[^\n]{0,40}?(?:/etc/(?:passwd|shadow|sudoers|ssh/|cron\.|hosts)|~/\.ssh/|C:\\Windows\\(?:System32|SysWOW64))', NULL, 'Write attempt against well-known sensitive system paths.', '{detector:tool-call-safety,risk:tampering,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('ece9aa28-4437-4838-8a44-255b0e30fa0b', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-fs-002', 'tool_call.filesystem', 'soft', '(?i)\.\.\/.{0,40}(?:etc|bin|boot|root|home)', NULL, 'Path-traversal segment escaping into a system directory.', '{detector:tool-call-safety,risk:traversal,severity:confidential}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('dab15ed2-97e8-4bdd-9e80-6419f9cdb953', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-ssrf-001', 'tool_call.ssrf', 'hard', '(?i)https?://(?:169\.254\.(?:\d{1,3}\.){2}\d{1,3}|localhost|127\.0\.0\.1|metadata\.google\.internal|instance-data\.ec2\.internal)', NULL, 'Cloud-metadata or loopback target in a URL.', '{detector:tool-call-safety,risk:ssrf,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('6685f82b-f326-46b5-bc63-091618a4dc11', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-ssrf-002', 'tool_call.ssrf', 'soft', '(?i)https?://(?:10\.\d{1,3}\.\d{1,3}\.\d{1,3}|192\.168\.\d{1,3}\.\d{1,3}|172\.(?:1[6-9]|2\d|3[01])\.\d{1,3}\.\d{1,3})', NULL, 'RFC1918 (private) IP target in a URL.', '{detector:tool-call-safety,risk:ssrf,severity:confidential}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('27ef7732-bb63-4fd4-84f6-8d3729161f67', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-ssrf-003', 'tool_call.ssrf', 'soft', '(?i)\.(?:internal|cluster\.local|svc\.cluster\.local)\b', NULL, 'Kubernetes / internal-service DNS suffix.', '{detector:tool-call-safety,risk:ssrf,severity:confidential}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('44f22102-15df-47bc-9cb7-652b6530e992', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-sql-001', 'tool_call.sqli', 'soft', '(?i)''\s*(?:or|union\s+select|--|;\s*drop\s+table|;\s*delete\s+from)', NULL, 'Classic tautology / piggy-back SQLi markers.', '{detector:tool-call-safety,risk:sqli,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('6150c1d9-b86b-4233-91af-52ac8d720954', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-sql-002', 'tool_call.sqli', 'soft', '(?i)\bxp_cmdshell\b|\bsys\.tables\b|\bxp_regread\b', NULL, 'SQL Server escape primitives commonly abused by injections.', '{detector:tool-call-safety,risk:sqli,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('5e86eeb7-71ec-4013-b08c-36178a3528c0', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-ev-001', 'tool_call.code_eval', 'hard', '(?i)\b(?:eval|exec)\s*\(\s*(?:request|req|user|input|arg)', NULL, 'Python-style eval/exec invoked on request / user-controlled input.', '{detector:tool-call-safety,risk:rce,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('adc36534-ad83-4ddb-bbec-1afef3016d64', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-ev-002', 'tool_call.code_eval', 'hard', '(?i)pickle\.loads?\s*\(|yaml\.load\s*\(|Marshal\.load\s*\(', NULL, 'Unsafe deserialization primitives (pickle / unsafe yaml.load / Ruby Marshal).', '{detector:tool-call-safety,risk:deserialization,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('82164f09-e64c-4981-a030-a207220bcd3e', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-db-001', 'tool_call.database', 'hard', '(?i)(?:drop\s+(?:table|database|schema)|truncate\s+table)\s+\w+', NULL, 'Destructive DDL (DROP / TRUNCATE) against a named object.', '{detector:tool-call-safety,risk:destructive,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('490f5db3-33c4-49d6-8e6f-2c1286d473e0', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-k8s-001', 'tool_call.kubernetes', 'soft', '(?i)kubectl\s+delete\s+(?:ns|namespace|deploy(?:ment)?|sts|pv|pvc)\s+\w+', NULL, 'kubectl delete against a high-impact resource type.', '{detector:tool-call-safety,risk:destructive,severity:restricted}');
INSERT INTO public.rule (id, "packId", "ruleId", category, severity, pattern, flags, description, labels) VALUES ('0602075d-d47c-4e67-8a67-3240fcaa806a', '34f93bac-06fa-4a46-860e-2bb18c5d5c8e', 'tc-env-001', 'tool_call.env_exfil', 'soft', '(?i)(?:os\.environ|process\.env|getenv)\s*\[\s*["''](?:AWS_|OPENAI_|ANTHROPIC_|GITHUB_|STRIPE_)', NULL, 'Programmatic read of a credential-prefixed environment variable.', '{detector:tool-call-safety,risk:exfiltration,severity:confidential}');
