INSERT INTO public.thing_config_template (type, config_key, state, version, updated_at, updated_by) VALUES ('agent', 'agent_settings', '{"quitAllowed": true, "shutdownWarning": {"en": "Closing Nexus Agent will stop AI traffic monitoring on this device. Your IT team will be notified. Are you sure?", "es": "Cerrar Nexus Agent detendrá la supervisión de tráfico de IA en este dispositivo. Se notificará a su equipo de TI. ¿Está seguro?", "zh": "关闭 Nexus Agent 将停止本设备上的 AI 流量监控。您的 IT 团队会收到通知。确定要关闭吗？"}, "autoUpdateChannel": "stable", "autoUpdateEnabled": true, "trafficUploadLevel": "processed", "shutdownWarningEnabled": true, "shutdownWarningMessage": "", "forceQUICFallbackBundles": ["com.google.Chrome", "com.google.Chrome.canary", "com.microsoft.edgemac", "com.brave.Browser", "company.thebrowser.Browser", "org.mozilla.firefox", "com.vivaldi.Vivaldi", "com.apple.Safari"]}', 6, '2026-05-15 04:03:01.992+00', 'configreconcile');
